import { Challenge, Receipt } from 'mppx';
import { Methods } from 'mppx/tempo';
import {
  err,
  ok,
  resultFromPromise,
  resultFromThrowable,
} from '@agentcash/neverthrow';

import { Mppx, tempo as tempoMethod } from 'mppx/client';

import { createClient, http } from 'viem';
import { tempo } from 'viem/chains';

import type { BaseMppError } from './types';
import type { Wallets } from '@/wallet';

const errorType = 'mpp';

export const mppOk = <T>(value: T) => ok(value);
export const mppErr = (surface: string, error: BaseMppError) =>
  err(errorType, surface, error);

const mppResultFromPromise = <T>(
  surface: string,
  promise: Promise<T>,
  error: (e: unknown) => BaseMppError
) => resultFromPromise(errorType, surface, promise, error);

const mppResultFromThrowable = <T>(
  surface: string,
  fn: () => T,
  error: (e: unknown) => BaseMppError
) => resultFromThrowable(errorType, surface, fn, error);

export const safeGetMppChallenge = (surface: string, response: Response) => {
  return mppResultFromThrowable(
    surface,
    () => Challenge.fromResponse(response, { methods: [Methods.charge] }),
    error => ({
      cause: 'parse_mpp_challenge',
      message:
        error instanceof Error
          ? error.message
          : 'Failed to parse MPP challenge from response',
    })
  );
};

export const safeCreateMppCredential = (
  surface: string,
  wallets: Wallets,
  response: Response
) => {
  const TEMPO_RPC_URL =
    'https://eng:acard-melody-fashion-finish@rpc.mainnet.tempo.xyz';

  const client = Mppx.create({
    polyfill: false,
    methods: [
      tempoMethod({
        account: wallets.evm,
        getClient: () =>
          createClient({
            chain: tempo,
            transport: http(TEMPO_RPC_URL),
          }),
      }),
    ],
  });

  return mppResultFromPromise(
    surface,
    client.createCredential(response),
    error => ({
      cause: 'create_mpp_credential',
      message:
        error instanceof Error
          ? error.message
          : 'Failed to create MPP credential',
    })
  );
};

export const safeGetMppReceipt = (surface: string, response: Response) => {
  return mppResultFromThrowable(
    surface,
    () => Receipt.fromResponse(response),
    error => ({
      cause: 'parse_mpp_receipt',
      message:
        error instanceof Error
          ? error.message
          : 'Failed to parse MPP receipt from response',
    })
  );
};
