import { caip2ToNetwork, Network } from '@agentcash/networks';

import { choosePaymentRequirement } from './choose-payment-requirement';

import { safeFetch } from '@/shared/neverthrow/fetch';
import {
  safeCreatePaymentPayload,
  safeGetPaymentRequired,
  safeGetPaymentSettlement,
  x402Err,
  x402Ok,
  x402ProbeClient,
} from '@/shared/protocols/x402';
import { tokenStringToNumber, formatUsd } from '@/shared/utils';

import { beforePayment } from '../before-payment';

import { PaymentProtocol } from '../types';

import type { ExecuteFetchResult } from '@/operations/fetch/types';
import type { HandlePaymentParams } from '../types';
import type { BaseX402Error } from './types';

/**
 * Detects whether a 402 response body indicates the Permit2 allowance failure.
 * The exact marker varies across facilitators ("permit2_allowance_required",
 * "invalid_exact_evm_permit2_payload_allowance_required", etc.), so we match
 * loosely on the two distinctive substrings.
 */
export const isPermit2AllowanceFailureBody = (body: string): boolean =>
  body.includes('permit2') && body.includes('allowance_required');

/**
 * Builds the user-facing error message for a Permit2-allowance failure.
 * Pulled out as a pure helper so it can be unit-tested without mocking the
 * whole payment pipeline.
 */
export const buildPermit2AllowanceErrorMessage = (params: {
  walletAddress: string;
  scheme: string;
}): string => {
  const { walletAddress, scheme } = params;
  return [
    `Payment failed: this endpoint's \`${scheme}\` scheme settles via the Permit2 contract, but your agentcash wallet (${walletAddress}) has not approved Permit2 to spend USDC.`,
    '',
    'The clean fix is server-side. The merchant should adopt the EIP-2612 gas-sponsoring extension — agentcash will then auto-sign an off-chain permit on each call and the facilitator pays the approval gas, with no setup required from the user. See https://docs.x402.org/extensions/eip2612-gas-sponsoring',
    '',
    `Until the merchant adopts that extension, you can do a one-time \`USDC.approve(0x000000000022D473030F116dDEE9F6B43aC78BA3, MAX_UINT256)\` on Base from this wallet (requires a small amount of ETH for gas, ~$0.01–0.10). After that, all future Permit2-based payments from this wallet work without further on-chain transactions.`,
  ].join('\n');
};

export async function handleX402Payment({
  response,
  request,
  options,
}: HandlePaymentParams) {
  const { surface, wallets } = options;
  const { timeout } = options.params;

  const paymentRequiredResult = await safeGetPaymentRequired(surface, response);

  if (paymentRequiredResult.isErr()) {
    return paymentRequiredResult;
  }

  const paymentRequired = paymentRequiredResult.value;

  if (paymentRequired.x402Version === 1) {
    return x402Err(surface, {
      cause: 'parse_payment_required' as const,
      message:
        'This endpoint uses the x402 v1 format, which is not supported by agentcash. Only x402 v2 servers (with an `accepts` array in the Payment-Required header) are supported.',
    });
  }

  if (!paymentRequired.accepts || !Array.isArray(paymentRequired.accepts)) {
    return x402Err(surface, {
      cause: 'parse_payment_required' as const,
      message:
        'This endpoint has a missing or malformed accepts array in the Payment-Required header.',
    });
  }

  // Check amount against maxAmount before any payment logic
  const accept = await choosePaymentRequirement({
    options,
    paymentRequirements: paymentRequired.accepts,
  });

  if (accept) {
    const amount = tokenStringToNumber(accept.amount);

    const typedNetwork = caip2ToNetwork(accept.network)!;
    if (!typedNetwork) {
      return x402Err(surface, {
        cause: 'parse_payment_required' as const,
        message: `Invalid network: ${accept.network}`,
      });
    }

    const beforePaymentResult = await beforePayment({
      options,
      balanceInput:
        typedNetwork === Network.SOLANA
          ? {
              address: wallets.svm.address,
              network: Network.SOLANA,
            }
          : {
              address: wallets.evm.address,
              network: typedNetwork,
            },
      amount,
      protocol: PaymentProtocol.X402,
    });

    if (beforePaymentResult.isErr()) {
      return beforePaymentResult;
    }
  }

  const paymentPayloadResult = await safeCreatePaymentPayload(
    surface,
    wallets,
    paymentRequired,
    accept ? () => accept : undefined
  );

  if (paymentPayloadResult.isErr()) {
    return paymentPayloadResult;
  }

  const paymentPayload = paymentPayloadResult.value;

  // Encode payment header
  const paymentHeaders =
    x402ProbeClient.encodePaymentSignatureHeader(paymentPayload);

  // Check if this is already a retry to prevent infinite loops
  if (
    request.headers.has('PAYMENT-SIGNATURE') ||
    request.headers.has('X-PAYMENT')
  ) {
    return x402Err(surface, {
      cause: 'payment_already_attempted',
      message: 'Payment already attempted',
    });
  }

  // Add payment headers to cloned request
  for (const [key, value] of Object.entries(paymentHeaders)) {
    request.headers.set(key, value);
  }
  request.headers.set(
    'Access-Control-Expose-Headers',
    'PAYMENT-RESPONSE,X-PAYMENT-RESPONSE'
  );

  // Retry the request with payment
  const paidResult = await safeFetch(surface, request, timeout);
  if (paidResult.isErr()) {
    return paidResult;
  }
  const paidResponse = paidResult.value;

  // Detect the Permit2-allowance-required failure and surface a clear,
  // actionable error before it becomes an opaque error upstream. Only reads
  // the body on non-2xx responses (where the body is always a small JSON
  // error object, never a streaming success response) and reads from a clone
  // so the original response body is untouched. See detectPermit2AllowanceError
  // for the full safety contract.
  const permit2Error = await detectPermit2AllowanceError(paidResponse, {
    walletAddress: wallets.evm.address,
    scheme: paymentPayload.accepted.scheme,
  });
  if (permit2Error) {
    return x402Err(surface, permit2Error);
  }

  const settlementResult = safeGetPaymentSettlement(surface, paidResponse);

  const settlement = settlementResult.isOk() ? settlementResult.value : null;

  const maxAmount = tokenStringToNumber(paymentPayload.accepted.amount);
  const settledAmount = settlement?.amount
    ? tokenStringToNumber(settlement.amount)
    : null;
  const isUpTo = paymentPayload.accepted.scheme === 'upto';

  const price =
    settledAmount != null
      ? formatUsd(settledAmount)
      : isUpTo
        ? `up to ${formatUsd(maxAmount)}`
        : formatUsd(maxAmount);

  return x402Ok<ExecuteFetchResult>({
    response: paidResponse,
    paymentInfo: {
      protocol: PaymentProtocol.X402,
      network: caip2ToNetwork(paymentPayload.accepted.network)!,
      price,
      payment: settlement
        ? {
            success: settlement.success,
            transactionHash: settlement.transaction,
          }
        : null,
    },
  });
}

/**
 * Defensive body-peek for the Permit2-allowance failure. Returns a
 * BaseX402Error if the response is the known failure mode, otherwise null.
 *
 * Safety properties:
 *   - Only reads on non-2xx (`!response.ok`); success responses are never
 *     touched. We use !ok rather than `=== 402` because while Surplus's
 *     facilitator returned 402 in our live test (per x402 spec), other
 *     facilitator implementations could plausibly return 400 (bad signature)
 *     or 500 (facilitator error) for the same underlying allowance failure.
 *     The body-marker check is the actual signal — the status filter is
 *     just a cheap gate to avoid reading streaming success bodies.
 *   - Reads from `response.clone()` so the original body stream is untouched
 *     and the caller can still consume it normally. clone() is safe here
 *     because handleX402Payment owns the first-and-only access to this
 *     response's body at this point in the pipeline.
 *   - text() rejection is absorbed via .catch — if the read fails for any
 *     reason, we degrade to returning null and the original response surfaces
 *     unchanged. The success path is never altered.
 */
async function detectPermit2AllowanceError(
  response: Response,
  context: { walletAddress: string; scheme: string }
): Promise<BaseX402Error | null> {
  if (response.ok) {
    return null;
  }
  const body = await response
    .clone()
    .text()
    .catch(() => '');
  if (!isPermit2AllowanceFailureBody(body)) {
    return null;
  }
  return {
    cause: 'permit2_allowance_required',
    message: buildPermit2AllowanceErrorMessage(context),
  };
}
