import { PaymentProtocol } from './types';

export function detectPaymentProtocols(response: Response): PaymentProtocol[] {
  const protocols: PaymentProtocol[] = [];

  const wwwAuth = response.headers.get('WWW-Authenticate');
  if (wwwAuth?.startsWith('Payment')) {
    protocols.push(PaymentProtocol.MPP);
  }

  const paymentRequired = response.headers.get('payment-required');
  if (paymentRequired) {
    protocols.push(PaymentProtocol.X402);
  }
  // If we couldn't detect either explicitly, default to x402
  if (protocols.length === 0) {
    protocols.push(PaymentProtocol.X402);
  }
  return protocols;
}
