import { fetchErr, fetchOk, safeFetch } from '@/shared/neverthrow/fetch';
import { BLACKLISTED_ORIGINS } from '@/shared/origins';

import { attemptSiwxAuth } from './auth';
import { executePayment } from './payment';

import type { ExecuteFetchOptions } from './types';
import { buildRequest } from '@/shared/request/build';
import type { RequestInput } from '@/shared/request/types';

/**
 * Executes a request with automatic SIWX authentication and payment handling.
 *
 * 1. Probe the endpoint
 * 2. If 402 with SIWX challenge, retry with SIGN-IN-WITH-X
 * 3. If still 402, execute payment
 */
export async function executeFetch(
  input: RequestInput,
  options: ExecuteFetchOptions
) {
  const request = buildRequest(input, options);

  const { surface } = options;
  const { timeout } = options.params;

  const blocked = BLACKLISTED_ORIGINS.find(origin =>
    request.url.startsWith(origin)
  );
  if (blocked) {
    return fetchErr(surface, {
      cause: 'network',
      message: `${blocked} is no longer available. This origin has been deprecated.`,
    });
  }

  const authRetryRequest = request.clone();
  const paymentRetryRequest = request.clone();

  const probeResult = await safeFetch(surface, request, timeout);

  if (probeResult.isErr()) {
    return fetchErr(surface, probeResult.error);
  }

  const initialResponse = probeResult.value;
  if (initialResponse.status !== 402) {
    return fetchOk({
      response: initialResponse,
      paymentInfo: null,
    });
  }

  const authResult = await attemptSiwxAuth(
    initialResponse,
    authRetryRequest,
    paymentRetryRequest,
    options
  );

  if (authResult.isErr()) {
    return authResult;
  }

  const latestResponse = authResult.value.response;
  if (latestResponse.status !== 402) {
    return fetchOk({
      response: latestResponse,
      paymentInfo: null,
    });
  }

  return executePayment(
    latestResponse,
    authResult.value.paymentRetryRequest,
    options
  );
}
