import {
  err,
  ok,
  resultFromPromise,
  resultFromThrowable,
} from '@agentcash/neverthrow';

import type { SelectPaymentRequirements } from '@x402/core/client';
import { x402Client, x402HTTPClient } from '@x402/core/client';

import { toClientEvmSigner } from '@x402/evm';
import { toClientSvmSigner } from '@x402/svm';

import { ExactEvmScheme } from '@x402/evm/exact/client';
import { UptoEvmScheme } from '@x402/evm/upto/client';
import { PatchedExactSvmScheme } from './patched-exact-svm-scheme';
import { capUptoDeadline } from './policies';

import { createSIWxPayload } from '@x402/extensions/sign-in-with-x';

import type { BaseX402Error } from './types';
import type { PaymentRequired } from '@x402/core/types';
import type {
  CompleteSIWxInfo,
  SIWxExtensionInfo,
  SolanaSigner,
  SupportedChain,
} from '@x402/extensions/sign-in-with-x';
import type { Wallets } from '@/wallet';
import { Network, networkToCaip2 } from '@agentcash/networks';
import type { Network as PaymentNetwork } from '@agentcash/networks';
import { createPublicClient, http } from 'viem';
import { base } from 'viem/chains';

const errorType = 'x402';

export const x402Ok = <T>(value: T) => ok(value);
export const x402Err = (cause: string, error: BaseX402Error) =>
  err(errorType, cause, error);

const x402ResultFromPromise = <T>(
  surface: string,
  promise: Promise<T>,
  error: (e: unknown) => BaseX402Error
) => resultFromPromise(errorType, surface, promise, error);

const x402ResultFromThrowable = <T>(
  surface: string,
  fn: () => T,
  error: (e: unknown) => BaseX402Error
) => resultFromThrowable(errorType, surface, fn, error);

export const x402ProbeClient = new x402HTTPClient(new x402Client());

export const safeGetPaymentRequired = (surface: string, response: Response) => {
  return x402ResultFromPromise(
    surface,
    response.json().then(
      json =>
        x402ProbeClient.getPaymentRequiredResponse(
          name => response.headers.get(name),
          json
        ),
      () =>
        x402ProbeClient.getPaymentRequiredResponse(name =>
          response.headers.get(name)
        )
    ),
    error => ({
      cause: 'parse_payment_required',
      message:
        error instanceof Error
          ? error.message
          : 'Failed to parse payment required',
    })
  );
};

export const getSiwxExtension = (
  extensions: PaymentRequired['extensions'],
  paymentNetwork?: PaymentNetwork
): CompleteSIWxInfo | undefined => {
  const siwx = extensions?.['sign-in-with-x'] as
    | { info?: SIWxExtensionInfo; supportedChains?: SupportedChain[] }
    | undefined;

  if (!siwx?.info) {
    return undefined;
  }

  const chain = siwx.supportedChains?.find(c =>
    paymentNetwork
      ? c.chainId === networkToCaip2(paymentNetwork)
      : c.chainId.startsWith('eip155:')
  );

  return {
    ...siwx.info,
    chainId: chain?.chainId ?? 'eip155:8453',
    type: chain?.type ?? 'eip191',
    signatureScheme: chain?.signatureScheme,
  };
};

export const safeCreatePaymentPayload = (
  surface: string,
  wallets: Wallets,
  paymentRequired: PaymentRequired,
  paymentRequirementsSelector?: SelectPaymentRequirements
) => {
  const client = new x402HTTPClient(
    x402Client.fromConfig({
      schemes: [
        {
          network: networkToCaip2(Network.BASE),
          client: new ExactEvmScheme(
            toClientEvmSigner(
              wallets.evm,
              createPublicClient({
                chain: base,
                transport: http(),
              })
            )
          ),
        },
        {
          network: networkToCaip2(Network.BASE),
          client: new UptoEvmScheme(
            toClientEvmSigner(
              wallets.evm,
              createPublicClient({
                chain: base,
                transport: http(),
              })
            )
          ),
        },
        {
          network: networkToCaip2(Network.SOLANA),
          client: new PatchedExactSvmScheme(toClientSvmSigner(wallets.svm)),
        },
      ],
      policies: [capUptoDeadline],
      paymentRequirementsSelector,
    })
  );
  return x402ResultFromPromise(
    surface,
    client.createPaymentPayload(paymentRequired),
    error => ({
      cause: 'create_payment_payload',
      message:
        error instanceof Error
          ? error.message
          : 'Failed to create payment payload',
    })
  );
};

export const safeGetPaymentSettlement = (
  surface: string,
  response: Response
) => {
  return x402ResultFromThrowable(
    surface,
    () =>
      x402ProbeClient.getPaymentSettleResponse(name =>
        response.headers.get(name)
      ),
    error => ({
      cause: 'get_payment_settlement',
      message:
        error instanceof Error
          ? error.message
          : 'Failed to get payment settlement',
    })
  );
};

export const safeCreateSIWxPayload = (
  surface: string,
  serverInfo: CompleteSIWxInfo,
  wallets: Wallets
) => {
  return x402ResultFromPromise(
    surface,
    createSIWxPayload(
      serverInfo,
      serverInfo.chainId.startsWith('eip155:')
        ? wallets.evm
        : (wallets.svm as unknown as SolanaSigner)
    ),
    error => ({
      cause: 'create_siwx_payload',
      message:
        error instanceof Error
          ? error.message
          : 'Failed to create SIWX payload',
    })
  );
};
