import type { Address } from 'viem';
import { formatUnits } from 'viem';

import { safeFetch } from '@/shared/neverthrow/fetch';
import {
  safeGetMppChallenge,
  safeCreateMppCredential,
  safeGetMppReceipt,
  mppErr,
  mppOk,
} from '@/shared/protocols/mpp';

import { PaymentProtocol } from '../types';
import { Network, EVM_CONFIGS } from '@agentcash/networks';
import { formatUsd } from '@/shared/utils';

import type { ExecuteFetchResult } from '@/operations/fetch/types';
import type { HandlePaymentParams } from '@/shared/protocols/types';
import { beforePayment } from '../before-payment';

export async function handleMppPayment({
  response,
  request,
  options,
}: HandlePaymentParams) {
  const { surface, wallets } = options;
  const { timeout } = options.params;

  // Prevent retry loops
  if (request.headers.has('Authorization')) {
    return mppErr(surface, {
      cause: 'mpp_payment_already_attempted',
      message: 'MPP payment already attempted',
    });
  }

  // Parse the challenge from the WWW-Authenticate header
  const challengeResult = safeGetMppChallenge(surface, response);

  if (challengeResult.isErr()) {
    return challengeResult;
  }

  const challenge = challengeResult.value;

  // Extract payment info from challenge request
  const amount = Number(formatUnits(BigInt(challenge.request.amount), 6));
  const tokenAddress = challenge.request.currency as Address;

  // Check that the requested token matches what agentcash supports on Tempo
  const expectedToken = EVM_CONFIGS[Network.TEMPO].usdcAddress.toLowerCase();
  if (tokenAddress.toLowerCase() !== expectedToken) {
    return mppErr(surface, {
      cause: 'unsupported_token',
      message: `Endpoint requires payment in token ${tokenAddress} on Tempo, but agentcash only supports ${EVM_CONFIGS[Network.TEMPO].usdcAddress}. The endpoint may be configured for a different token (e.g. PathUSD vs USDC).`,
    });
  }

  const beforePaymentResult = await beforePayment({
    options,
    balanceInput: {
      address: wallets.evm.address,
      network: Network.TEMPO,
      tokenAddress,
    },
    amount,
    protocol: PaymentProtocol.MPP,
  });

  if (beforePaymentResult.isErr()) {
    return beforePaymentResult;
  }

  const credentialResult = await safeCreateMppCredential(
    surface,
    wallets,
    response
  );

  if (credentialResult.isErr()) {
    return credentialResult;
  }

  const credential = credentialResult.value;

  // Set Authorization header on cloned request
  request.headers.set('Authorization', credential);

  // Retry the fetch with the credential
  const paidFetchResult = await safeFetch(surface, request, timeout);
  if (paidFetchResult.isErr()) {
    return paidFetchResult;
  }

  const paidResponse = paidFetchResult.value;

  // If the server still returns 402, the payment was rejected
  if (paidResponse.status === 402) {
    const body = await paidResponse
      .clone()
      .text()
      .catch(() => '');
    const detail = body ? `: ${body}` : '';
    return mppErr(surface, {
      cause: 'mpp_payment_rejected',
      message: `MPP payment was rejected by the server (402)${detail}`,
    });
  }

  // Parse the receipt for transaction hash
  const receiptResult = safeGetMppReceipt(surface, paidResponse);

  return mppOk<ExecuteFetchResult>({
    response: paidResponse,
    paymentInfo: {
      protocol: PaymentProtocol.MPP,
      network: Network.TEMPO,
      price: formatUsd(amount),
      payment: receiptResult.isOk()
        ? {
            success: true,
            transactionHash: receiptResult.value.reference,
          }
        : null,
    },
  });
}
