import type { PaymentPolicy } from '@x402/core/client';

/**
 * Maximum deadline (in seconds) we accept for `upto` payment requirements.
 *
 * The `upto` Permit2 signature is bound by `paymentRequirements.maxTimeoutSeconds`,
 * which the SDK passes straight through from the merchant's 402 response with no
 * upper bound. Within that window, the (merchant + facilitator) pair can settle
 * for any amount in `[0, cap]` — and the only on-chain check is the deadline.
 *
 * A long deadline therefore extends the window of facilitator-discretion settlement
 * at the signed cap. 7 days lets a long-running agent keep working without
 * re-signing, but bounds the trust window if a merchant declares an unreasonably
 * large `maxTimeoutSeconds` (accidentally or otherwise).
 *
 * `exact` requirements are unaffected: their amount is fixed in the signature, so
 * a long validity window is just an annoyance, not a discretion surface.
 */
export const MAX_UPTO_DEADLINE_SECONDS = 7 * 24 * 60 * 60; // 7 days

/**
 * Caps `maxTimeoutSeconds` on `upto` requirements at {@link MAX_UPTO_DEADLINE_SECONDS}.
 * Leaves `exact` and any other scheme untouched. Pass to `x402Client.fromConfig({ policies })`.
 */
export const capUptoDeadline: PaymentPolicy = (_x402Version, requirements) =>
  requirements.map(r =>
    r.scheme === 'upto' && r.maxTimeoutSeconds > MAX_UPTO_DEADLINE_SECONDS
      ? { ...r, maxTimeoutSeconds: MAX_UPTO_DEADLINE_SECONDS }
      : r
  );
