import { detectPaymentProtocols } from '@/shared/protocols/detect';
import { handleMppPayment } from '@/shared/protocols/mpp/handle-payment';
import { pickByBalance } from '@/shared/protocols/pick';
import { PaymentProtocol } from '@/shared/protocols/types';
import { handleX402Payment } from '@/shared/protocols/x402/handle-payment';

import type { ExecuteFetchOptions } from './types';

export async function executePayment(
  response: Response,
  request: Request,
  options: ExecuteFetchOptions
) {
  const { paymentProtocol } = options.params;

  const params = {
    response,
    request,
    options,
  };

  if (paymentProtocol) {
    return handlerMap[paymentProtocol](params);
  }

  const available = detectPaymentProtocols(response);
  const preferred =
    available.length === 1
      ? available[0]!
      : await pickByBalance(response, options);
  const fallback =
    available.length > 1
      ? preferred === PaymentProtocol.MPP
        ? PaymentProtocol.X402
        : PaymentProtocol.MPP
      : null;

  const fallbackRetryRequest = fallback ? request.clone() : null;
  const result = await handlerMap[preferred](params);

  if (result.isErr() && fallback && fallbackRetryRequest) {
    return handlerMap[fallback]({
      ...params,
      request: fallbackRetryRequest,
    });
  }

  return result;
}

const handlerMap = {
  [PaymentProtocol.MPP]: handleMppPayment,
  [PaymentProtocol.X402]: handleX402Payment,
};
