import { safeGetMppChallenge } from '@/shared/protocols/mpp';

import { log } from '@/shared/log';
import { getBalance } from '@/shared/balance';
import { Network } from '@agentcash/networks';

import { PaymentProtocol } from './types';

import type { ExecuteFetchOptions } from '@/operations/fetch/types';

/**
 * Pick the preferred protocol by comparing wallet balances.
 * Falls back to 'mpp' if both balances fail to fetch.
 */
export async function pickByBalance(
  response: Response,
  options: ExecuteFetchOptions
): Promise<PaymentProtocol> {
  const { surface, wallets, flags } = options;

  // Get x402 (USDC on Base and Solana) balances in parallel
  const x402Balances = await Promise.all([
    getBalance(
      surface,
      {
        address: wallets.evm.address,
        network: Network.BASE,
      },
      flags
    ),
    getBalance(
      surface,
      {
        address: wallets.svm.address,
        network: Network.SOLANA,
      },
      flags
    ),
  ]);

  const x402Balance = x402Balances.reduce(
    (acc, balance) => acc + (balance.isOk() ? balance.value.balance : 0),
    0
  );

  // Get MPP (Tempo) balance — need token address from the challenge
  let mppBalance = 0;
  const challengeResult = safeGetMppChallenge(surface, response);
  if (challengeResult.isOk()) {
    const currency = challengeResult.value.request.currency;
    if (currency) {
      const tempoResult = await getBalance(
        surface,
        {
          address: wallets.evm.address,
          network: Network.TEMPO,
        },
        flags
      );
      if (tempoResult.isOk()) {
        mppBalance = tempoResult.value.balance ?? 0;
      }
    }
  }

  log.info(`Protocol selection — x402: $${x402Balance}, mpp: $${mppBalance}`);
  return x402Balance >= mppBalance ? PaymentProtocol.X402 : PaymentProtocol.MPP;
}
