import { getBalance } from '@/shared/balance';
import { caip2ToNetwork, Network, networkToCaip2 } from '@agentcash/networks';

import type { PaymentRequirements } from '@x402/core/types';
import type { ExecuteFetchOptions } from '@/operations/fetch/types';

interface ChoosePaymentRequirementParams {
  paymentRequirements: PaymentRequirements[];
  options: ExecuteFetchOptions;
}

// Prefer `upto` over `exact` when a server offers both on the same network.
// `upto` authorizes a maximum via Permit2 and settles for actual usage, which
// matches usage-priced endpoints (e.g. per-token LLM inference) better than
// `exact`, which charges the upper bound regardless. Servers that surface
// both schemes — like Surplus Intelligence — explicitly recommend preferring
// `upto`. Falls back to the first match when `upto` isn't offered.
export const preferUpto = (
  requirements: PaymentRequirements[]
): PaymentRequirements | undefined => {
  return requirements.find(pr => pr.scheme === 'upto') ?? requirements[0];
};

export const choosePaymentRequirement = async ({
  paymentRequirements,
  options,
}: ChoosePaymentRequirementParams) => {
  const { surface, wallets, flags } = options;
  const { paymentNetwork } = options.params;
  if (paymentNetwork) {
    const caip2 = networkToCaip2(paymentNetwork);
    return preferUpto(paymentRequirements.filter(pr => pr.network === caip2));
  }

  const requirementsWithBalance = await Promise.all(
    paymentRequirements.map(async pr => {
      const network = caip2ToNetwork(pr.network);
      if (network === null) {
        return {
          balance: 0,
          requirement: pr,
        };
      }
      if (network === Network.SOLANA) {
        const balanceResult = await getBalance(
          surface,
          {
            address: wallets.svm.address,
            network,
          },
          flags
        );
        return {
          requirement: pr,
          balance: balanceResult.isOk() ? balanceResult.value.balance : 0,
        };
      } else {
        const balanceResult = await getBalance(
          surface,
          {
            address: wallets.evm.address,
            network,
          },
          flags
        );
        return {
          requirement: pr,
          balance: balanceResult.isOk() ? balanceResult.value.balance : 0,
        };
      }
    })
  );
  const bestNetwork = requirementsWithBalance.sort(
    (a, b) => b.balance - a.balance
  )[0]!.requirement.network;
  return preferUpto(
    paymentRequirements.filter(pr => pr.network === bestNetwork)
  );
};
