import {
  getSetComputeUnitLimitInstruction,
  setTransactionMessageComputeUnitPrice,
} from '@solana-program/compute-budget';
import { TOKEN_PROGRAM_ADDRESS } from '@solana-program/token';
import {
  fetchMint,
  findAssociatedTokenPda,
  getTransferCheckedInstruction,
  TOKEN_2022_PROGRAM_ADDRESS,
} from '@solana-program/token-2022';
import {
  appendTransactionMessageInstructions,
  createTransactionMessage,
  getBase64EncodedWireTransaction,
  partiallySignTransactionMessageWithSigners,
  pipe,
  prependTransactionMessageInstruction,
  setTransactionMessageFeePayer,
  setTransactionMessageLifetimeUsingBlockhash,
  type Address,
} from '@solana/kit';

import type {
  PaymentPayload,
  PaymentRequirements,
  SchemeNetworkClient,
} from '@x402/core/types';
import {
  DEFAULT_COMPUTE_UNIT_LIMIT,
  DEFAULT_COMPUTE_UNIT_PRICE_MICROLAMPORTS,
  createRpcClient,
  type ClientSvmConfig,
  type ClientSvmSigner,
  type ExactSvmPayloadV2,
} from '@x402/svm';

type BlockhashLifetime = Parameters<
  typeof setTransactionMessageLifetimeUsingBlockhash
>[0];

interface PatchedPaymentExtra {
  feePayer?: Address;
  recentBlockhash?:
    | string
    | Partial<{
        blockhash: string;
        lastValidBlockHeight: bigint | number | string;
      }>;
  lastValidBlockHeight?: bigint | number | string;
}

function parseLastValidBlockHeight(
  value: bigint | number | string | undefined
): bigint | undefined {
  if (typeof value === 'bigint') {
    return value;
  }

  if (typeof value === 'number' && Number.isFinite(value)) {
    return BigInt(value);
  }

  if (typeof value === 'string' && value.length > 0) {
    return BigInt(value);
  }

  return undefined;
}

function asBlockhash(blockhash: string): BlockhashLifetime['blockhash'] {
  return blockhash as BlockhashLifetime['blockhash'];
}

/**
 * Local compatibility patch for Coinbase ExactSvmScheme.
 *
 * Changes from upstream:
 * - omits the trailing memo instruction
 * - prefers paymentRequirements.extra.recentBlockhash when provided
 */
export class PatchedExactSvmScheme implements SchemeNetworkClient {
  readonly scheme = 'exact';

  constructor(
    private readonly signer: ClientSvmSigner,
    private readonly config?: ClientSvmConfig
  ) {}

  async createPaymentPayload(
    x402Version: number,
    paymentRequirements: PaymentRequirements
  ): Promise<Pick<PaymentPayload, 'x402Version' | 'payload'>> {
    const rpc = createRpcClient(
      paymentRequirements.network,
      this.config?.rpcUrl
    );

    const tokenMint = await fetchMint(
      rpc,
      paymentRequirements.asset as Address
    );
    const tokenProgramAddress = tokenMint.programAddress;

    if (
      tokenProgramAddress.toString() !== TOKEN_PROGRAM_ADDRESS.toString() &&
      tokenProgramAddress.toString() !== TOKEN_2022_PROGRAM_ADDRESS.toString()
    ) {
      throw new Error('Asset was not created by a known token program');
    }

    const [sourceATA] = await findAssociatedTokenPda({
      mint: paymentRequirements.asset as Address,
      owner: this.signer.address,
      tokenProgram: tokenProgramAddress,
    });

    const [destinationATA] = await findAssociatedTokenPda({
      mint: paymentRequirements.asset as Address,
      owner: paymentRequirements.payTo as Address,
      tokenProgram: tokenProgramAddress,
    });

    const transferIx = getTransferCheckedInstruction(
      {
        source: sourceATA,
        mint: paymentRequirements.asset as Address,
        destination: destinationATA,
        authority: this.signer,
        amount: BigInt(paymentRequirements.amount),
        decimals: tokenMint.data.decimals,
      },
      { programAddress: tokenProgramAddress }
    );

    const extra = paymentRequirements.extra as PatchedPaymentExtra;
    const feePayer = extra.feePayer;

    if (!feePayer) {
      throw new Error(
        'feePayer is required in paymentRequirements.extra for SVM transactions'
      );
    }

    const latestBlockhash = await this.resolveBlockhashLifetime(rpc, extra);

    const tx = pipe(
      createTransactionMessage({ version: 0 }),
      tx =>
        setTransactionMessageComputeUnitPrice(
          DEFAULT_COMPUTE_UNIT_PRICE_MICROLAMPORTS,
          tx
        ),
      tx => setTransactionMessageFeePayer(feePayer, tx),
      tx =>
        prependTransactionMessageInstruction(
          getSetComputeUnitLimitInstruction({
            units: DEFAULT_COMPUTE_UNIT_LIMIT,
          }),
          tx
        ),
      tx => appendTransactionMessageInstructions([transferIx], tx),
      tx => setTransactionMessageLifetimeUsingBlockhash(latestBlockhash, tx)
    );

    const signedTransaction =
      await partiallySignTransactionMessageWithSigners(tx);
    const base64EncodedWireTransaction =
      getBase64EncodedWireTransaction(signedTransaction);

    const payload: ExactSvmPayloadV2 = {
      transaction: base64EncodedWireTransaction,
    };

    return {
      x402Version,
      payload,
    };
  }

  private async resolveBlockhashLifetime(
    rpc: ReturnType<typeof createRpcClient>,
    extra: PatchedPaymentExtra
  ): Promise<BlockhashLifetime> {
    const providedLastValidBlockHeight = parseLastValidBlockHeight(
      extra.lastValidBlockHeight
    );

    if (typeof extra.recentBlockhash === 'string') {
      if (providedLastValidBlockHeight !== undefined) {
        return {
          blockhash: asBlockhash(extra.recentBlockhash),
          lastValidBlockHeight: providedLastValidBlockHeight,
        };
      }

      const { value } = await rpc.getLatestBlockhash().send();
      return {
        blockhash: asBlockhash(extra.recentBlockhash),
        lastValidBlockHeight: value.lastValidBlockHeight,
      };
    }

    if (
      extra.recentBlockhash &&
      typeof extra.recentBlockhash === 'object' &&
      typeof extra.recentBlockhash.blockhash === 'string'
    ) {
      const lastValidBlockHeight =
        parseLastValidBlockHeight(extra.recentBlockhash.lastValidBlockHeight) ??
        providedLastValidBlockHeight;

      if (lastValidBlockHeight !== undefined) {
        return {
          blockhash: asBlockhash(extra.recentBlockhash.blockhash),
          lastValidBlockHeight,
        };
      }

      const { value } = await rpc.getLatestBlockhash().send();
      return {
        blockhash: asBlockhash(extra.recentBlockhash.blockhash),
        lastValidBlockHeight: value.lastValidBlockHeight,
      };
    }

    return (await rpc.getLatestBlockhash().send()).value;
  }
}
